// validate + แปลงจำนวนเงิน → satang (Omise ใช้หน่วย satang = บาท*100)
const b = $json.body || {};
const amount = Number(b.amount);
if (!amount || amount <= 0) {
  throw new Error('amount required');
}
return [{
  json: {
    amount_satang: Math.round(amount * 100),
    amount: amount,
    payment_type: b.payment_type || 'general',
    ref_no: b.ref_no || '',
    customer_name: b.customer_name || '',
    customer_phone: b.customer_phone || '',
    description: b.description || '',
    created_by: b.created_by || 'system',
    branch_code: b.branch_code || '',
    branch_name: b.branch_name || ''
  }
}];

// บันทึก charge ลง DB + map response กลับให้ UI
const charge = $json;
const src = charge.source || {};
const scan = src.scannable_code || {};
const img = (scan.image && (scan.image.download_uri || scan.image)) || '';
const prep = $('Prepare Charge').item.json;
return [{
  json: {
    charge_id: charge.id,
    source_id: src.id || '',
    qr_image: img,
    amount: prep.amount,
    status: charge.status === 'successful' ? 'paid' : (charge.status || 'pending'),
    expires_at: charge.expires_at || null,
    created_at: charge.created_at || new Date().toISOString(),
    ref_no: prep.ref_no,
    customer_name: prep.customer_name,
    customer_phone: prep.customer_phone,
    description: prep.description,
    payment_type: prep.payment_type,
    created_by: prep.created_by,
    branch_code: prep.branch_code,
    branch_name: prep.branch_name,
    raw_omise: JSON.stringify(charge)
  }
}];
